var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_NULL","text":{"KOREA":"역시 당신이 이곳의 사장이었나.","JPN":"やはりお前がここの社長だったのか。","ENG":"I knew it. So you are the CEO of this place.","TWN":"你果然就是這裡的老闆嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_NULL","text":{"KOREA":"하지만 설마 내 앞에 모습을 드러낼 줄은 몰랐군. 나와 눈을 마주친다는 것이 어떤 의미인지, 너도 잘 알고 있을텐데?","JPN":"しかし、まさか俺に姿を晒すとはな。俺と目を合わせることがどういう意味か、お前なら知っていると思うが？","ENG":"But I didn't expect you to show yourself in front of me. You must know the consequences of making eye contact with me, don't you?","TWN":"不過我倒是沒想到你會向我透露你的真實身分，畢竟你應該也很清楚，和我對到眼會發生什麼事。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_NULL","text":{"KOREA":"훗, 농담이야. 신세를 진 사람에게 함부로 기아스를 걸지는 않아.","JPN":"ふっ、冗談だよ。世話になった相手にギアスをかけることはしない。","ENG":"Hah, I'm joking. I wouldn't dare abuse my Geass to someone I'm indebted to.","TWN":"呵，開玩笑的。你幫過我，我不會輕易對恩人施展Geass的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_NULL","text":{"KOREA":"이 힘은 브리타니아를 부수고 새로운 세계를 만들기 위한 힘. 나는 나나리가 안심하고 살아갈 수 있는 세계를 위해…….","JPN":"この力はブリタニアを破壊し、新しい世界をつくるための力。俺はナナリーが安心して暮らせる世界のために……。","ENG":"This power is to collapse Britannia and create a new world order. All I want is a world where Nunnally can live in peace...","TWN":"這股力量是用來毀滅不列顛尼亞創造一個新世界的。我要為娜娜莉打造一個可以安心生活的世界……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_NULL","text":{"KOREA":"아니, 역시 너와는 관계 없는 이야기군.","JPN":"いや、お前には関係のない話だ。","ENG":"Oh, this has nothing to do with you.","TWN":"沒事，這跟你沒關係。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_NULL","text":{"KOREA":"그래서 하고 싶은 말은 뭐지?","JPN":"それで言いたいことは何だ？","ENG":"So? What is it that you want to say?","TWN":"你想跟我說什麼？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_NULL","text":{"KOREA":"종신 계약? 하하, 말도 안 되는 소리를.","JPN":"これは、終身契約？　ははっ。何を馬鹿なことを。","ENG":"A lifetime contract? Ha ha! Don't be ridiculous.","TWN":"嗯？終身契約？哈哈，說什麼傻話？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_NULL","text":{"KOREA":"미안하지만 나는 이미 마녀와 계약을 해버려서 말이야. 이 이상의 계약은 사양하겠어.","JPN":"悪いが俺は既に魔女と契約しているんでな。これ以上の契約は遠慮させてもらう。","ENG":"I'm sorry, but I already have a contract with the witch. One is enough, so I'll have to pass on this one.","TWN":"抱歉，我早已和魔女簽訂契約，而且並不打算再簽其他契約。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_NULL","text":{"KOREA":"뭐…… 그 대신, 이곳에서 신세를 지는 동안에는 잠시 너의 힘을 빌려주지.","JPN":"まあ……その代わり、ここで世話になる間はお前に力を貸そう。","ENG":"Well... Instead, I'll lend you my strength while I'm here.","TWN":"這樣吧……我在這裡打擾的這段時間，就將我的力量借給你吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_NULL","text":{"KOREA":"너에게도 이런 저런 사정이 있는 것 같으니까 말이야.","JPN":"お前にも色々な事情があるらしいしな。","ENG":"I see you are dealing with your own issues as well.","TWN":"我看你似乎也有不少苦衷。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};